INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ee00ff87-cd5a-4bc3-8e36-192a1583d4c5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Flutter OTA Updates — When EAS Update and CodePush Are Safe to Use$escape$,
  $escape$Flutter apps can be updated over-the-air (OTA) using Firebase's EAS Update or Microsoft's CodePush. However, these services differ significantly. EAS Update uses a binary delta algorithm to send only the changed code, reducing the update size. CodePush, on the other hand, sends the entire app bundle. Use EAS Update for apps with frequent updates, while CodePush is suitable for apps with less frequent updates. Ensure that your app's dependencies are up-to-date before using EAS Update.$escape$,
  $escape$import 'package:flutter/foundation.dart';
import 'package:firebase_inappmessaging_platform_interface/firebase_inappmessaging_platform_interface.dart';

void main() {
  if (kIsWeb) {
    // Use CodePush for web
  } else {
    // Use EAS Update for mobile
  }
}$escape$,
  $escape$dart$escape$,
